diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 394dfca262e1..a68cbbc49775 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3856,6 +3856,21 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
       }
     }
   }
+  // select(C2, select(C1, a, b), select(C1, b, a)) -> select(C1 ^ C2, b, a)
+  // This handles the case where we select between two symmetric selects.
+  if (SelectInst *TrueSI = dyn_cast<SelectInst>(TrueVal)) {
+    if (SelectInst *FalseSI = dyn_cast<SelectInst>(FalseVal)) {
+      if (TrueSI->getCondition()->getType() == FalseSI->getCondition()->getType() &&
+          TrueSI->getCondition()->getType() == CondVal->getType() &&
+          TrueSI->getTrueValue() == FalseSI->getFalseValue() &&
+          TrueSI->getFalseValue() == FalseSI->getTrueValue() &&
+          TrueSI->hasOneUse() && FalseSI->hasOneUse()) {
+        Value *XorCond = Builder.CreateXor(CondVal, TrueSI->getCondition());
+        return SelectInst::Create(XorCond, TrueSI->getFalseValue(),
+                                  TrueSI->getTrueValue());
+      }
+    }
+  }

